#include <stdio.h>
int main() {
    int T, N, M, K;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d %d %d", &N, &M, &K);
        if (N == 1 || M == 1) {
            printf("%d\n", K);
        } else {
            int denom = N + M - 2;
            int ans = (K + denom - 1) / denom; // ceiling division
            printf("%d\n", ans);
        }
    }
    return 0;
}

