import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it)); K = int(next(it))
        if N == 1 or M == 1:
            out.append(str(K))
        else:
            denom = N + M - 2
            ans = (K + denom - 1) // denom
            out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

